class ModelRecommender:
    def __init__(self, df):
        self.df = df

    def recommend(self, ram_gb=16, use_case="general"):
        max_params = ram_gb // 2
        weights = {
            "general": {"Average ⬆️": 1.0},
            "reasoning": {"BBH": 0.4, "MATH Lvl 5": 0.4, "GPQA": 0.2},
        }
        w = weights.get(use_case, weights["general"])
        cands = self.df[self.df["#Params (B)"] <= max_params].copy()
        cands["score"] = sum(cands[c] * v for c, v in w.items())
        return cands.nlargest(3, "score")[["model", "score"]]

rec = ModelRecommender(df)
print(rec.recommend(ram_gb=16, use_case="reasoning"))
